
import { defineComponent } from "vue";
import AddSupportModal from "./AddSupportModal.vue";
import SupportCard from "./SupportCard.vue";
import SupportCardJson from "@/assets/support_card_data.json";

type CardInfo = { detail: typeof SupportCardJson[number]; diamond: number; level: number };

export default defineComponent({
  components: {
    AddSupportModal,
    SupportCard,
  },

  data: function () {
    type DeckType = { name: string; deck: { id: number; diamond: number; level: number }[] };
    let cards: (CardInfo | null)[] = [null, null, null, null, null, null];
    let savedDecks: DeckType[] = [];

    return {
      cards,
      selectedIndex: 0,
      deckName: "",
      selectedDeckName: "",
      showUpdateCardModal: false,
      showDeckNameModal: false,
      savedDecks,
      publicPath: process.env.BASE_URL,
    };
  },

  props: {
    displayContent: {
      type: String,
      required: true,
    },
    left: {
      type: Boolean,
      required: true,
    },
  },

  computed: {
    cardStats: function (): ({ icon: number[]; text: string }[] | null)[] {
      let stats: ({ icon: number[]; text: string }[] | null)[] = [];

      for (const card of this.cards) {
        // null
        if (card == null) {
          stats.push(null);
          continue;
        }

        let effectArray = new Array<number>(32).fill(0);

        // support effects
        for (const supportEffect of card.detail.effect) {
          let lo = { lv: -1, value: -1 };
          let hi = { lv: -1, value: -1 };

          for (let i = card.level / 5; i >= 0; --i) {
            if (supportEffect.value[i] !== -1) {
              lo = { lv: i * 5, value: supportEffect.value[i] };
              break;
            }
          }

          for (let i = card.level / 5; i <= 10; ++i) {
            if (supportEffect.value[i] !== -1) {
              hi = { lv: i * 5, value: supportEffect.value[i] };
              break;
            }
          }

          if (lo.value === -1) {
            // do nothing
          } else if (hi.value === -1 || lo.lv == hi.lv) {
            effectArray[supportEffect.type] = lo.value;
          } else {
            const v = lo.value + ((card.level - lo.lv) * (hi.value - lo.value)) / (hi.lv - lo.lv);
            effectArray[supportEffect.type] = Math.floor(v);
          }
        }

        // unique effects
        if (card.detail.unique != null && card.level >= card.detail.unique.lv) {
          for (const uniqueEffect of card.detail.unique.effect) {
            const ty = uniqueEffect.type;
            if ([1, 19].includes(ty) && effectArray[ty] !== 0) {
              // 友情ボーナス / 得意率
              const v = ((100 + effectArray[ty]) * (100 + uniqueEffect.value) - 10000) / 100;
              effectArray[ty] = v;
            } else {
              effectArray[ty] += uniqueEffect.value;
            }
          }
        }

        let stat: { icon: number[]; text: string }[] = [];
        const effectPer = [1, 2, 8, 15, 16, 18, 25, 26, 27, 28];
        const defaultPush = (index: number) => {
          const text =
            effectArray[index] === 0
              ? "-"
              : (effectPer.includes(index) ? "" : "+") +
                effectArray[index].toString() +
                (effectPer.includes(index) ? "%" : "");
          stat.push({ icon: [], text });
        };

        defaultPush(1); // 友情
        defaultPush(2); // やる気

        // 練習ボーナス
        let trainingBonus: { icon: number[]; text: string } | null = null;
        for (let i = 3; i < 8; ++i) {
          if (effectArray[i] > 0) {
            if (trainingBonus == null) {
              trainingBonus = { icon: [i - 3], text: "+" + effectArray[i].toString() };
            } else {
              if (trainingBonus.text !== "+" + effectArray[i].toString()) {
                trainingBonus = { icon: [], text: "Error!" };
                break;
              }
              trainingBonus.icon.push(i - 3);
            }
          }
        }
        stat.push(trainingBonus ?? { icon: [], text: "-" });

        defaultPush(8); // トレ効果

        // 初期ボーナス
        let initialBonus: { icon: number[]; text: string } | null = null;
        for (let i = 9; i < 14; ++i) {
          if (effectArray[i] > 0) {
            if (initialBonus == null) {
              initialBonus = { icon: [i - 9], text: "+" + effectArray[i].toString() };
            } else {
              if (initialBonus.text !== "+" + effectArray[i].toString()) {
                initialBonus = { icon: [], text: "Error!" };
                break;
              }
              initialBonus.icon.push(i - 9);
            }
          }
        }
        stat.push(initialBonus ?? { icon: [], text: "-" });

        defaultPush(14); // 初期絆
        defaultPush(15); // レース
        defaultPush(16); // ファン数
        defaultPush(17); // ヒントLv
        defaultPush(18); // ヒント発生率
        defaultPush(19); // 得意率
        defaultPush(25); // イベ回復量
        defaultPush(26); // イベ効果
        defaultPush(27); // 失敗率
        defaultPush(28); // 体力消費
        defaultPush(30); // スキルPt
        defaultPush(31); // 賢さ友情回復量

        stats.push(stat);
      }

      return stats;
    },
  },

  methods: {
    updateCard: function (index: number) {
      this.selectedIndex = index;
      this.showUpdateCardModal = true;
    },

    select: function (arg: CardInfo | null) {
      const currentCard = this.cards[this.selectedIndex];
      if (currentCard == null && arg == null) return;
      if (
        currentCard == null ||
        arg == null ||
        currentCard.detail.id !== arg.detail.id ||
        currentCard.diamond !== arg.diamond
      ) {
        this.cards[this.selectedIndex] = arg;
        this.selectedDeckName = "";
      }
    },

    loadDeck: function () {
      if (this.selectedDeckName === "") return;

      let selectedDeck: { id: number; diamond: number; level: number }[] = [];
      for (const deck of this.savedDecks) {
        if (deck.name === this.selectedDeckName) {
          selectedDeck = deck.deck;
        }
      }

      const supportCards = Object.fromEntries(SupportCardJson.map((card) => [card.id, card]));
      for (let i = 0; i < 6; ++i) {
        if (selectedDeck[i].id === -1) {
          this.cards[i] = null;
        } else {
          this.cards[i] = {
            detail: supportCards[selectedDeck[i].id],
            diamond: selectedDeck[i].diamond,
            level: selectedDeck[i].level,
          };
        }
      }
    },

    saveDeck: function () {
      this.showDeckNameModal = true;
      this.deckName = this.selectedDeckName;
      setTimeout(() => (this.$refs.deckNameInput as HTMLInputElement).focus(), 10);
    },

    saveDeckName: function () {
      if (this.deckName === "") return;

      let deck: { id: number; diamond: number; level: number }[] = [];
      for (const card of this.cards) {
        if (card == null) {
          deck.push({ id: -1, diamond: -1, level: -1 });
        } else {
          deck.push({ id: card.detail.id, diamond: card.diamond, level: card.level });
        }
      }

      let updated = false;
      for (let i = 0; i < this.savedDecks.length; ++i) {
        if (this.savedDecks[i].name === this.deckName) {
          updated = true;
          this.savedDecks[i].deck = deck;
        }
      }

      if (!updated) {
        this.savedDecks.push({ name: this.deckName, deck });
      }

      this.selectedDeckName = this.deckName;
      this.closeDeckNameModal();

      localStorage.setItem("savedDecks", JSON.stringify(this.savedDecks));
    },

    closeDeckNameModal: function () {
      this.deckName = "";
      this.showDeckNameModal = false;
    },

    removeDeck: function () {
      if (this.selectedDeckName === "") return;

      for (let i = 0; i < this.savedDecks.length; ++i) {
        if (this.savedDecks[i].name === this.selectedDeckName) {
          this.savedDecks.splice(i, 1);
          break;
        }
      }

      this.selectedDeckName = "";
      if (this.savedDecks.length > 0) {
        localStorage.setItem("savedDecks", JSON.stringify(this.savedDecks));
      } else {
        localStorage.removeItem("savedDecks");
      }
    },

    resetDeck: function () {
      this.cards = [null, null, null, null, null, null];
    },
  },

  mounted: function () {
    const data = localStorage.getItem("savedDecks");
    if (data != null) {
      try {
        this.savedDecks = JSON.parse(data);
      } catch (e) {
        localStorage.removeItem("savedDecks");
      }
    }
  },
});
