<template>
  <div class="flex flex-wrap items-center justify-center w-full xl:h-44 xl:mb-3">
    <div
      v-for="i in 6"
      :key="i"
      class="inline-block relative m-0.5 support-card"
      :style="{ width: 'calc((100% - 28px) / 6)', 'max-width': '90px' }"
    >
      <support-card
        v-if="cards[i - 1] != null"
        :id="cards[i - 1].detail.id"
        :rarity="cards[i - 1].detail.rarity"
        :type="cards[i - 1].detail.command_id"
        :diamond="cards[i - 1].diamond"
        :level="cards[i - 1].level"
        :absolute="true"
        width="100%"
        @click="updateCard(i - 1)"
      />
      <div
        v-else
        class="absolute cursor-pointer shadow-inner rounded-lg border-2 border-gray-300"
        :style="{
          width: 100 * (87 / 90) + '%',
          height: 100 * (87 / 90) + '%',
          left: 100 * (1.5 / 90) + '%',
          top: 100 * (1 / 90) + '%',
        }"
        @click="updateCard(i - 1)"
      >
        <img
          :src="`${publicPath}img/icon/utx_ico_plus_00.png`"
          class="absolute left-1/2 top-1/2"
          :style="{ width: '24%', transform: 'translate(-50%, -50%)' }"
        />
      </div>
    </div>

    <!-- Deck select -->
    <div
      class="flex items-center justify-center w-full xl:h-12 my-3 sm:mt-4 sm:mb-5 xl:mt-1 xl:mb-0"
    >
      <select
        v-model="selectedDeckName"
        :class="
          'ml-1.5 sm:ml-2 mr-2.5 sm:mr-3 px-2 py-0.5 sm:py-1 w-44 sm:w-56 ' +
          'rounded-md text-xs sm:text-sm'
        "
        @change="loadDeck"
      >
        <option value="">
          {{ savedDecks.length === 0 ? "--- デッキなし ---" : "--- 未選択 ---" }}
        </option>
        <option v-for="item in savedDecks" :key="item.name" :value="item.name">
          {{ item.name }}
        </option>
      </select>

      <button
        :class="
          'hover:bg-gray-200 border border-gray-600 rounded-xl shadow ' +
          'mx-1.5 sm:mx-2 px-3 sm:px-4 py-0.5 sm:py-1 text-xs sm:text-sm disabled:opacity-40'
        "
        @click="removeDeck"
        :disabled="selectedDeckName === ''"
      >
        削除
      </button>

      <button
        :class="
          'hover:bg-gray-200 border border-gray-600 rounded-xl shadow ' +
          'mx-1.5 sm:mx-2 px-3 sm:px-4 py-0.5 sm:py-1 text-xs sm:text-sm'
        "
        @click="saveDeck"
      >
        保存
      </button>

      <button
        :class="
          'hidden sm:block hover:bg-gray-200 border border-gray-600 rounded-xl shadow ' +
          'mx-1.5 sm:mx-2 px-3 sm:px-4 py-0.5 sm:py-1 text-xs sm:text-sm'
        "
        @click="resetDeck"
      >
        リセット
      </button>
    </div>

    <!-- Reset button -->
    <div class="sm:hidden flex justify-end w-full mb-3 pr-4">
      <button
        :class="
          'hover:bg-gray-100 border border-gray-600 rounded-xl shadow ' +
          'mx-1 xl:mx-2 px-3 xl:px-4 py-0.5 xl:py-1 text-xs sm:text-sm'
        "
        @click="resetDeck"
      >
        デッキをリセット
      </button>
    </div>
  </div>

  <!-- Stats -->
  <div v-if="displayContent === 'stats'" class="flex flex-col w-full">
    <div
      v-for="statIndex in 17"
      :key="statIndex"
      :class="
        'flex items-center justify-center w-full h-11 sm:h-14 xl:h-8 ' +
        'text-sm sm:text-base ' +
        (statIndex % 2 === 1 ? 'bg-gray-200' : '')
      "
    >
      <div
        class="hidden sm:block h-full flex-grow"
        :class="!left ? 'xl:h-0' : ''"
        style="background-color: #f9f8fd"
      />
      <div
        class="flex flex-wrap items-center justify-center h-full"
        style="width: 564px; max-width: 100%"
      >
        <div
          :class="
            'xl:hidden flex items-center justify-center w-full h-5 xl:h-auto ' +
            'text-xs sm:text-base font-bold'
          "
        >
          {{
            [
              "友情ボーナス",
              "やる気効果アップ",
              "トレーニングボーナス",
              "トレーニング効果アップ",
              "初期ステータス値アップ",
              "初期絆ゲージアップ",
              "レースボーナス",
              "ファン数ボーナス",
              "ヒントLvアップ",
              "ヒント発生率アップ",
              "得意率アップ",
              "イベント回復量アップ",
              "イベント効果アップ",
              "失敗率ダウン",
              "体力消費ダウン",
              "スキルPtボーナス",
              "賢さ友情回復量アップ",
            ][statIndex - 1]
          }}
        </div>
        <div
          v-for="cardIndex in 6"
          :key="cardIndex"
          class="flex mx-0.5 items-center justify-center h-5 xl:h-auto"
          :style="{ width: '90px', 'max-width': 'calc((100% - 28px) / 6)' }"
        >
          <div class="flex items-center" v-if="cardStats[cardIndex - 1] != null">
            <img
              v-for="iconId in cardStats[cardIndex - 1][statIndex - 1].icon"
              :key="iconId"
              :src="`${publicPath}img/icon/utx_ico_obtain_0${iconId}.png`"
              class="mr-0.5 sm:mr-1 w-4 sm:w-5"
            />
            <span>{{ cardStats[cardIndex - 1][statIndex - 1].text }}</span>
          </div>
        </div>
      </div>
      <div
        class="hidden sm:block h-full flex-grow"
        :class="left ? 'xl:h-0' : ''"
        style="background-color: #f9f8fd"
      />
    </div>
  </div>

  <!-- Training details -->
  <div v-else></div>

  <!-- Update Card Modal -->
  <add-support-modal
    v-model:show="showUpdateCardModal"
    v-model:cards="cards"
    v-model:deckIndex="selectedIndex"
    @select="select"
  />

  <!-- Save deck modal -->
  <transition name="modal">
    <div
      v-if="showDeckNameModal"
      :class="
        'flex fixed inset-0 w-full h-full z-40 items-center justify-center ' +
        'bg-gray-500 bg-opacity-60'
      "
      @click.self="closeDeckNameModal"
    >
      <!-- Modal -->
      <div
        :class="
          'z-50 flex flex-wrap justify-center m-3 sm:m-4 px-2 sm:px-6 py-2 sm:py-3 ' +
          'rounded-xl overflow-y-hidden shadow-xl'
        "
        style="background-color: #f9f8fd"
      >
        <div class="px-3 sm:px-0 py-2">
          <form @submit.prevent="saveDeckName">
            <input
              type="text"
              ref="deckNameInput"
              v-model="deckName"
              class="w-72 rounded-md shadow-sm py-1.5 sm:py-2 text-sm sm:text-base"
              placeholder="デッキ名"
            />
          </form>
        </div>
        <div class="flex flex-grow justify-end py-2">
          <button
            :class="
              'inline-flex justify-center rounded-md border border-gray-300 shadow-sm ' +
              'sm:ml-4 px-3 sm:px-5 py-1.5 sm:py-2 w-auto text-sm sm:text-base ' +
              'bg-white hover:bg-gray-50 ' +
              'focus:outline-none focus:ring-2 focus:ring-offset-2 focus:ring-blue-500'
            "
            @click="closeDeckNameModal"
          >
            閉じる
          </button>
          <button
            :class="
              'inline-flex justify-center rounded-md border border-transparent shadow-sm ' +
              'mx-3 sm:ml-4 sm:mr-0 px-3 sm:px-5 py-1.5 sm:py-2 w-auto text-sm sm:text-base ' +
              'bg-green-600 text-white hover:bg-green-700 ' +
              'focus:outline-none focus:ring-2 focus:ring-offset-2 focus:ring-green-500 ' +
              'disabled:opacity-40 disabled:bg-green-600 disabled:cursor-not-allowed'
            "
            :disabled="deckName === ''"
            @click="saveDeckName"
          >
            決定
          </button>
        </div>
      </div>
    </div>
  </transition>
</template>

<script lang="ts">
import { defineComponent } from "vue";
import AddSupportModal from "./AddSupportModal.vue";
import SupportCard from "./SupportCard.vue";
import SupportCardJson from "@/assets/support_card_data.json";

type CardInfo = { detail: typeof SupportCardJson[number]; diamond: number; level: number };

export default defineComponent({
  components: {
    AddSupportModal,
    SupportCard,
  },

  data: function () {
    type DeckType = { name: string; deck: { id: number; diamond: number; level: number }[] };
    let cards: (CardInfo | null)[] = [null, null, null, null, null, null];
    let savedDecks: DeckType[] = [];

    return {
      cards,
      selectedIndex: 0,
      deckName: "",
      selectedDeckName: "",
      showUpdateCardModal: false,
      showDeckNameModal: false,
      savedDecks,
      publicPath: process.env.BASE_URL,
    };
  },

  props: {
    displayContent: {
      type: String,
      required: true,
    },
    left: {
      type: Boolean,
      required: true,
    },
  },

  computed: {
    cardStats: function (): ({ icon: number[]; text: string }[] | null)[] {
      let stats: ({ icon: number[]; text: string }[] | null)[] = [];

      for (const card of this.cards) {
        // null
        if (card == null) {
          stats.push(null);
          continue;
        }

        let effectArray = new Array<number>(32).fill(0);

        // support effects
        for (const supportEffect of card.detail.effect) {
          let lo = { lv: -1, value: -1 };
          let hi = { lv: -1, value: -1 };

          for (let i = card.level / 5; i >= 0; --i) {
            if (supportEffect.value[i] !== -1) {
              lo = { lv: i * 5, value: supportEffect.value[i] };
              break;
            }
          }

          for (let i = card.level / 5; i <= 10; ++i) {
            if (supportEffect.value[i] !== -1) {
              hi = { lv: i * 5, value: supportEffect.value[i] };
              break;
            }
          }

          if (lo.value === -1) {
            // do nothing
          } else if (hi.value === -1 || lo.lv == hi.lv) {
            effectArray[supportEffect.type] = lo.value;
          } else {
            const v = lo.value + ((card.level - lo.lv) * (hi.value - lo.value)) / (hi.lv - lo.lv);
            effectArray[supportEffect.type] = Math.floor(v);
          }
        }

        // unique effects
        if (card.detail.unique != null && card.level >= card.detail.unique.lv) {
          for (const uniqueEffect of card.detail.unique.effect) {
            const ty = uniqueEffect.type;
            if ([1, 19].includes(ty) && effectArray[ty] !== 0) {
              // 友情ボーナス / 得意率
              const v = ((100 + effectArray[ty]) * (100 + uniqueEffect.value) - 10000) / 100;
              effectArray[ty] = v;
            } else {
              effectArray[ty] += uniqueEffect.value;
            }
          }
        }

        let stat: { icon: number[]; text: string }[] = [];
        const effectPer = [1, 2, 8, 15, 16, 18, 25, 26, 27, 28];
        const defaultPush = (index: number) => {
          const text =
            effectArray[index] === 0
              ? "-"
              : (effectPer.includes(index) ? "" : "+") +
                effectArray[index].toString() +
                (effectPer.includes(index) ? "%" : "");
          stat.push({ icon: [], text });
        };

        defaultPush(1); // 友情
        defaultPush(2); // やる気

        // 練習ボーナス
        let trainingBonus: { icon: number[]; text: string } | null = null;
        for (let i = 3; i < 8; ++i) {
          if (effectArray[i] > 0) {
            if (trainingBonus == null) {
              trainingBonus = { icon: [i - 3], text: "+" + effectArray[i].toString() };
            } else {
              if (trainingBonus.text !== "+" + effectArray[i].toString()) {
                trainingBonus = { icon: [], text: "Error!" };
                break;
              }
              trainingBonus.icon.push(i - 3);
            }
          }
        }
        stat.push(trainingBonus ?? { icon: [], text: "-" });

        defaultPush(8); // トレ効果

        // 初期ボーナス
        let initialBonus: { icon: number[]; text: string } | null = null;
        for (let i = 9; i < 14; ++i) {
          if (effectArray[i] > 0) {
            if (initialBonus == null) {
              initialBonus = { icon: [i - 9], text: "+" + effectArray[i].toString() };
            } else {
              if (initialBonus.text !== "+" + effectArray[i].toString()) {
                initialBonus = { icon: [], text: "Error!" };
                break;
              }
              initialBonus.icon.push(i - 9);
            }
          }
        }
        stat.push(initialBonus ?? { icon: [], text: "-" });

        defaultPush(14); // 初期絆
        defaultPush(15); // レース
        defaultPush(16); // ファン数
        defaultPush(17); // ヒントLv
        defaultPush(18); // ヒント発生率
        defaultPush(19); // 得意率
        defaultPush(25); // イベ回復量
        defaultPush(26); // イベ効果
        defaultPush(27); // 失敗率
        defaultPush(28); // 体力消費
        defaultPush(30); // スキルPt
        defaultPush(31); // 賢さ友情回復量

        stats.push(stat);
      }

      return stats;
    },
  },

  methods: {
    updateCard: function (index: number) {
      this.selectedIndex = index;
      this.showUpdateCardModal = true;
    },

    select: function (arg: CardInfo | null) {
      const currentCard = this.cards[this.selectedIndex];
      if (currentCard == null && arg == null) return;
      if (
        currentCard == null ||
        arg == null ||
        currentCard.detail.id !== arg.detail.id ||
        currentCard.diamond !== arg.diamond
      ) {
        this.cards[this.selectedIndex] = arg;
        this.selectedDeckName = "";
      }
    },

    loadDeck: function () {
      if (this.selectedDeckName === "") return;

      let selectedDeck: { id: number; diamond: number; level: number }[] = [];
      for (const deck of this.savedDecks) {
        if (deck.name === this.selectedDeckName) {
          selectedDeck = deck.deck;
        }
      }

      const supportCards = Object.fromEntries(SupportCardJson.map((card) => [card.id, card]));
      for (let i = 0; i < 6; ++i) {
        if (selectedDeck[i].id === -1) {
          this.cards[i] = null;
        } else {
          this.cards[i] = {
            detail: supportCards[selectedDeck[i].id],
            diamond: selectedDeck[i].diamond,
            level: selectedDeck[i].level,
          };
        }
      }
    },

    saveDeck: function () {
      this.showDeckNameModal = true;
      this.deckName = this.selectedDeckName;
      setTimeout(() => (this.$refs.deckNameInput as HTMLInputElement).focus(), 10);
    },

    saveDeckName: function () {
      if (this.deckName === "") return;

      let deck: { id: number; diamond: number; level: number }[] = [];
      for (const card of this.cards) {
        if (card == null) {
          deck.push({ id: -1, diamond: -1, level: -1 });
        } else {
          deck.push({ id: card.detail.id, diamond: card.diamond, level: card.level });
        }
      }

      let updated = false;
      for (let i = 0; i < this.savedDecks.length; ++i) {
        if (this.savedDecks[i].name === this.deckName) {
          updated = true;
          this.savedDecks[i].deck = deck;
        }
      }

      if (!updated) {
        this.savedDecks.push({ name: this.deckName, deck });
      }

      this.selectedDeckName = this.deckName;
      this.closeDeckNameModal();

      localStorage.setItem("savedDecks", JSON.stringify(this.savedDecks));
    },

    closeDeckNameModal: function () {
      this.deckName = "";
      this.showDeckNameModal = false;
    },

    removeDeck: function () {
      if (this.selectedDeckName === "") return;

      for (let i = 0; i < this.savedDecks.length; ++i) {
        if (this.savedDecks[i].name === this.selectedDeckName) {
          this.savedDecks.splice(i, 1);
          break;
        }
      }

      this.selectedDeckName = "";
      if (this.savedDecks.length > 0) {
        localStorage.setItem("savedDecks", JSON.stringify(this.savedDecks));
      } else {
        localStorage.removeItem("savedDecks");
      }
    },

    resetDeck: function () {
      this.cards = [null, null, null, null, null, null];
    },
  },

  mounted: function () {
    const data = localStorage.getItem("savedDecks");
    if (data != null) {
      try {
        this.savedDecks = JSON.parse(data);
      } catch (e) {
        localStorage.removeItem("savedDecks");
      }
    }
  },
});
</script>

