<template>
  <div
    class="inline-block cursor-pointer support-card"
    ref="supportCardDiv"
    :class="{ absolute, 'inset-0': absolute, relative: !absolute }"
    :style="{ width, 'max-width': maxWidth }"
  >
    <img
      :src="`${publicPath}img/support/support_thumb_${id}.png`"
      class="absolute top-0 w-full h-full"
    />
    <img
      :src="`${publicPath}img/icon/supportcard_rarity_0${rarity}.png`"
      class="absolute"
      :class="{
        'rarity-s': !large,
        'rarity-l': large,
      }"
    />
    <img
      :src="`${publicPath}img/icon/utx_ico_obtain_0${type}.png`"
      class="absolute"
      :class="{
        'type-s': !large,
        'type-l': large,
      }"
    />
    <div v-if="diamond !== -1">
      <div
        class="absolute"
        :class="{
          'bottom-bar': true,
          'bottom-bar-s': !large,
          'bottom-bar-l': large,
        }"
      />
      <img
        v-for="i in 4"
        :key="`diamond-${4 - i}`"
        :src="`${publicPath}img/icon/utx_ico_limit_0${+(4 - i < diamond)}.png`"
        class="absolute"
        :class="{
          [`diamond-${4 - i}-s`]: !large,
          [`diamond-${4 - i}-l`]: large,
        }"
      />
      <div
        class="absolute font-bold text-right leading-none"
        :class="{
          level: true,
          'level-s': !large,
          'level-l': large,
        }"
        :style="`font-size: ${fontSize}`"
      >
        Lv{{ level }}
      </div>
    </div>
  </div>
</template>

<script lang="ts">
import { defineComponent } from "vue";

export default defineComponent({
  name: "SupportCard",

  data: function () {
    return {
      publicPath: process.env.BASE_URL,
      fontSize: "0px",
    };
  },

  props: {
    id: { type: Number, required: true },
    rarity: { type: Number, required: true },
    type: { type: Number, required: true },
    diamond: { type: Number, default: -1 },
    level: { type: Number, default: -1 },
    width: { type: String, default: "256px" },
    maxWidth: { type: String, default: "none" },
    absolute: { type: Boolean, default: false },
    large: { type: Boolean, default: false },
  },

  mounted: function () {
    this.updateFontSize();
    window.addEventListener("resize", this.updateFontSize);
  },

  beforeUnmount: function () {
    window.removeEventListener("resize", this.updateFontSize);
  },

  methods: {
    updateFontSize: function () {
      const width = (this.$refs.supportCardDiv as HTMLDivElement).clientWidth;
      this.fontSize = (this.large ? 46.5 : 51) * (width / 512) + "pt";
    },
  },
});
</script>

